  createNode(nodes, aiId, rootId, "AI Features", "IdiamPro includes powerful AI capabilities to help you generate content, create images, and build outlines faster. AI features are accessed through the violet sparkles icon and the image button in the toolbar.", []);

  // AI Plans
  createNode(nodes, aiPlansId, aiId, "AI Plans (FREE vs PREMIUM)", "IdiamPro offers two AI plans:\n\nFREE Plan:\n- AI content generation\n- External source ingestion\n- Standard AI processing\n\nPREMIUM Plan ($9.99/month):\n- All FREE features\n- AI image generation\n- Advanced AI model\n- Subtree summaries\n- Teach mode\n- Consistency checks\n- Priority processing\n- RAG-powered knowledge base (coming soon): Semantic search across all your outlines using vector embeddings for faster, more accurate cross-outline queries\n\nTo manage your plan: Click the AI menu (sparkles icon) > 'Manage AI Plan...'");

  // AI Menu
  createNode(nodes, aiMenuId, aiId, "Smart Tools menu", "Access intelligent features from a single menu:\n\n1. Click the sparkles icon in the toolbar — this is the Smart Tools menu (renamed 2026-06-04; previously \"AI Features\")\n2. The menu shows:\n   - Quick Command — type or speak any natural-language request (also ⌘K)\n   - Reformat with AI… — restructure a node's content (or a selection) per a plain-language instruction (\"turn into a bulleted list\", \"make each line a heading\")\n   - Generate Subtree from Topic — builds out a structured subtree under the selected node\n   - Translate this section — translate a subtree into another language\n   - Ask Your Outlines — search your outlines with natural language (previously \"Knowledge Chat\")\n\nResearch & Import has its own home in the toolbar's Import menu (BookDown icon), not the Smart Tools menu, so source-merging lives next to the other import actions. The Import menu also hosts \"Link to Outline…\" for inserting a cross-outline link node, and \"Refresh from Web\" (moved here 2026-06-06 — it brings external web content INTO existing nodes, so it fits the Import metaphor).\n\nYour current plan (Free or Premium) is shown in the menu header.");

  // Generate Outline from Topic
  createNode(nodes, aiGenerateOutlineId, aiId, "Generate Subtree from Topic", "Create a structured subtree from any topic under the selected node:\n\n1. Select a node in your outline\n2. Click AI menu > 'Generate Subtree from Topic'\n3. The topic field is pre-filled with the selected node's name — edit it if you want\n4. Choose depth, tone, and level settings\n5. Click 'Generate'\n6. AI creates a structured subtree as children of the selected node\n\nThis is great for building out sections of an existing outline. For example, select a node called 'Market Analysis', generate a subtree, and you'll get sub-sections like 'Competitor Landscape', 'Target Demographics', etc.");

  // Generate Content for Node
  createNode(nodes, aiGenerateContentId, aiId, "Generate Content for Node", "AI can write detailed content for any node in your outline.\n\nThe AI analyzes your node's title and its position in the hierarchy to generate relevant, contextual content. You control whether to replace existing content, append to it, or cancel.\n\nThe generation considers your outline structure from root to the selected node, ensuring thematic consistency.", []);
  createNode(nodes, aiGenerateHowId, aiGenerateContentId, "How to Trigger", "1. Select any node (except root)\n2. Click the violet sparkles button in the content pane header\n3. AI generates content based on the node's title and context");
  createNode(nodes, aiGenerateContextId, aiGenerateContentId, "Context & Input", "The AI uses:\n- The node's name/title\n- The path of ancestor nodes (for context)\n- Any existing content (as a draft to consider)\n\nThis helps AI generate relevant, contextual content that fits your outline structure.");
  createNode(nodes, aiGenerateConflictId, aiGenerateContentId, "Replace vs Append", "If the node already has content, you'll see options:\n\n- Replace: Overwrite existing content with AI content\n- Append Below: Add AI content after existing content\n- Cancel: Keep existing content unchanged\n\nYour content is never changed without your explicit choice.");

  // Research & Import (formerly Ingest External Source)
  createNode(nodes, aiIngestId, aiId, "Research & Import", "The Research & Import feature is the heart of IdiamPro's power. Import content from multiple sources simultaneously, and AI will synthesize them into a unified, structured outline.\n\n**Key Capabilities:**\n• Multi-source synthesis - Import multiple sources at once, AI finds connections\n• Smart defaults - YouTube titles, AI-generated names, automatic introductions\n• Merge or create new - Default merges into current outline, or create fresh\n• Speaker diarization - Audio recordings identify different speakers\n\n**Access:** Toolbar Import menu (BookDown icon) > 'Research & Import'. (Previously lived under the AI menu; moved 2026-06-04 so all import surfaces sit together.)", []);
  createNode(nodes, aiIngestSourcesId, aiIngestId, "Supported Sources", "**YouTube Videos**\n• Paste any YouTube URL\n• Transcript extracted automatically\n• Video title becomes default outline name\n\n**Conversation/Audio**\n• Paste transcript directly\n• Upload audio file for transcription\n• Record live with microphone\n• Speaker diarization identifies who said what\n\n**Documents**\n• PDF files (URL or upload)\n• Word, Excel, PowerPoint\n• Images with OCR text extraction\n\n**Other**\n• Web pages (URL)\n• Plain text/notes\n• Existing outline files (.idm)\n• Video files (audio extracted)");
  createNode(nodes, aiIngestPreviewId, aiIngestId, "Smart Naming & Summaries", "**Automatic Outline Naming:**\n• YouTube videos → Uses video title\n• Other sources → AI generates concise title from content\n• Fallback → Date-based name\n\n**Root Node Introduction:**\nWhen creating a new outline (not merging), the root node automatically gets an AI-generated introduction that summarizes all the content below it. This helps readers quickly understand the context.\n\n**Chapter Introductions:**\nParent/chapter nodes include introductory content that previews their children - no empty headers.");
  createNode(nodes, aiIngestMergeId, aiIngestId, "Merge vs New Outline", "**Default: Merge into Current Outline**\n• New content is synthesized with your existing outline\n• AI finds connections between old and new material\n• Preserves your existing structure\n• Content from both existing and new sources is integrated under shared themes\n\n**Option: Create New Outline**\n• Check 'Create new outline instead'\n• Provide a name or let AI generate one\n• Your current outline is unchanged\n\nThe merge behavior ensures you can continuously build knowledge on a topic from multiple sources over time.\n\n**Node Formatting:**\nResearch outlines use short names (2-6 words) as tree labels with detailed content in the content pane. Even in comprehensive mode, node names stay concise while all prose and detail goes into the content field.");

  // Pending Import Recovery
  const pendingImportId = uuidv4();
  createNode(nodes, pendingImportId, aiIngestId, "Pending Import Recovery", "On the desktop (Electron) app, if a Research & Import operation times out or the app closes during an import, the result is saved automatically.\n\nOn next launch:\n1. A recovery dialog appears\n2. It shows the pending import that was interrupted\n3. You can choose to apply the import or discard it\n\nThis ensures you never lose a long-running import due to network issues or accidental app closure.");

  // Undo Merge
  const undoMergeId = uuidv4();
  createNode(nodes, undoMergeId, aiIngestId, "Unmerge", "When merging research into an existing outline, a snapshot of your outline is taken before the merge begins.\n\nIf the merge produces bad results, look for the **Unmerge button** in the toolbar — it appears right after the Research & Import button as an orange circular arrow icon. Clicking it restores your outline to its exact pre-merge state.\n\nThe Unmerge button persists until you click it or perform another merge (which creates a new backup). You can freely edit the outline and still unmerge later. The backup survives app restarts. Only the most recent merge can be unmerged.");

  // AI Image Generation
  createNode(nodes, aiImageGenId, aiId, "AI Image Generation (Premium)", "Create custom illustrations with AI:\n\n1. Click the violet Image button in the content toolbar\n2. Describe the image you want (be specific about style, colors, composition)\n3. Choose an aspect ratio (square, landscape, portrait)\n4. Click 'Generate Image'\n\nThe AI-generated image is inserted directly into your content.\n\n**Tips for better results:**\n• Be specific: 'A serene mountain lake at sunset with purple sky' vs 'a lake'\n• Mention style: 'digital art', 'watercolor', 'photorealistic', 'minimalist'\n• Include composition details: 'close-up', 'wide angle', 'from above'\n\n**Note:** This feature requires a Premium plan.");

  // Generate Podcast
  createNode(nodes, aiPodcastId, aiId, "Generate Podcast", "Convert any subtree into a conversational audio podcast.\n\nHow to use:\n1. Right-click any node in the outline\n2. Select 'Generate Podcast'\n3. Configure your podcast:\n   • **Style**: Two-Host Discussion, Single Narrator, Interview, or Debate\n   • **Voices**: Choose from 6 OpenAI voices for each speaker\n   • **Length**: Brief (2-3 min), Standard (5-8 min), or Detailed (10-15 min)\n   • **Quality**: Standard (faster) or HD (higher quality)\n4. Click 'Generate' and wait for the AI to write the script and synthesize audio\n5. Preview the audio in the built-in player\n6. Click 'Save Audio File' to save the MP3\n\nThe script viewer lets you read along with the generated dialogue. You can also discard and regenerate with different settings.\n\nYour podcast preferences (style, voices, length, and audio quality) are remembered across sessions, so you don't need to reconfigure each time. When switching to a new style for the first time, your preferred voices carry over automatically.\n\n**Requirements:** Requires an OpenAI API key (OPENAI_API_KEY) in your environment for text-to-speech.");

  // Create Content for Descendants
  const aiDescendantsId = uuidv4();
  createNode(nodes, aiDescendantsId, aiId, "Create Content for Descendants", "Generate AI content for all child nodes of a parent at once.\n\nHow to use:\n1. Right-click a parent node (one that has children)\n2. Select 'Create Content for Descendants'\n3. AI generates content for every child node based on its title and context\n\nThis is a fast way to flesh out an entire section of your outline. Each child node receives content tailored to its title and position in the hierarchy. Existing content in child nodes is preserved - only empty nodes get new content.");

  createNode(nodes, aiLiveBooksId, aiId, "Refresh from Web", "Refresh from Web keeps your documents from going stale. It takes a node and everything under it, asks AI to refresh the content against the latest information on the internet, and shows you exactly what would change before anything is touched. (Internal code name: LIVE BOOKS — that name still appears in some technical files but not in the UI.)\n\nHow to use:\n1. Select the node you want to refresh (select the top/root node to refresh the whole outline)\n2. Open it one of three ways:\n   • Toolbar: Import menu (BookDown icon) > 'Refresh from Web' (moved here 2026-06-06 — it brings external web content INTO existing nodes, so it fits the Import metaphor)\n   • Command Palette (Cmd/Ctrl+K) > 'Refresh from Web'\n   • Keyboard: Cmd+Shift+R (Mac) / Ctrl+Shift+R (Windows/Linux)\n3. Choose how to update:\n   • Merge & augment (recommended) — keeps content that's still accurate, fixes what's outdated, folds in new developments\n   • Overwrite / regenerate — rewrites each section from scratch\n4. By default you get a side-by-side preview of every proposed change. Accept or reject each node individually, then click Apply. Nothing changes until you approve.\n5. (Optional) Tick 'Apply automatically without previewing' before running if you want changes applied directly — this is off by default and must be turned on deliberately each time.\n\nWhat it protects:\n• Nodes you edited by hand are automatically skipped so the refresh never clobbers your own writing. Skipped nodes are listed in the preview with an 'Include anyway' button if you want them refreshed too.\n\nSources & attribution:\n• Every refreshed node carries its sources. A small 'Sources' chip appears on the node — click it to see the citations and which AI model produced the refresh (e.g. 'Refreshed with Gemini 3.5 Flash'). Citations travel with the outline through save and export.\n• With cloud AI, refreshes use live web search and list the real pages used. With local AI (no internet), the refresh uses the model's built-in knowledge and clearly states that no web sources were available — it never invents citations.\n\nRefresh from Web is personal and local: it only changes your own copy of the outline after you approve.");

  // Translate (#52) — built on the same transform engine as LIVE BOOKS.
  const aiTranslateId = uuidv4();
  createNode(nodes, aiTranslateId, aiId, "Translate this section", "Translate any node and its descendants into another language, with the same preview-and-approve safety as Refresh from Web.\n\nBuilt for globally distributed teams (Boston ↔ Shanghai ↔ São Paulo): the language list is ordered so the most-requested global collaboration languages — Chinese (Simplified), Portuguese (Brazilian), Spanish, French, Japanese, Korean, German, Italian, Hindi — appear at the top.\n\nHow to use:\n1. Select the node you want to translate (select the top/root to translate the whole outline)\n2. Open it one of two ways:\n   • Toolbar: Smart Tools menu (sparkles icon) > 'Translate this section'\n   • Command Palette (Cmd/Ctrl+K) > 'Translate this section'\n3. Pick a target language from the dropdown (no default — you have to choose). Optionally tick 'Use local AI' to keep the translation entirely on your machine via Ollama.\n4. Click 'Translate & preview'. Each node's translation is shown side-by-side with the original. Reject any you don't want, then click 'Apply N translations'.\n\nFormatting (headings, lists, bold, links) is preserved. Proper nouns and code stay as-is. Nodes you edited by hand are auto-skipped with a per-node 'Include anyway' override, so translation never clobbers your edits.\n\nUsage: One Translate (regardless of how many nodes are in the subtree) counts as ONE generation against your monthly cap. Bring your own API key in Settings for unlimited use.");

  // Reformat with AI — single-shot per-node content reformat driven by a
  // plain-language instruction.
  const aiReformatId = uuidv4();
  createNode(nodes, aiReformatId, aiId, "Reformat with AI", "Reformat the content in a node by describing the format you want in plain English. Same workflow you'd use with an AI assistant for cleanup — built into the app.\n\nHow to open it:\n• Smart Tools menu (sparkles icon) > 'Reformat with AI…' — reformats the whole node\n• Right-click anywhere in the content area > 'Reformat with AI…' — reformats the whole node, or just your selection if text is selected\n• Select some text in the content editor — the floating formatting toolbar (bubble menu) shows a violet wand button at the LEFT END with a small 'Most Powerful' badge; click it to reformat just the selection (moved to first position 2026-06-05 to make it the eye-magnet of the toolbar)\n• Command Palette (Cmd/Ctrl+K) > 'Reformat with AI…'\n\nThe dialog:\n1. Type the format you want — e.g. 'turn into a bulleted list', 'make each line a heading', 'convert to a markdown table', 'tighten spacing and remove empty lines'.\n2. Or click one of the example chips below the input to fill it in.\n3. Click 'Preview reformat'. The AI returns a reformatted version, shown side-by-side with the original.\n4. Click 'Apply' to keep it, 'Modify instruction' to tweak and try again, or 'Cancel' to discard.\n\nWhat it preserves: Your actual words and meaning. Reformat changes structure and presentation — it doesn't invent new content or delete substance unless you explicitly ask it to summarise.\n\nOptional: Tick 'Use local AI (Ollama)' to run the reformat entirely on-device.\n\nUsage: One reformat = ONE generation against your monthly cap, regardless of how long the content is. Available on every tier (Free trial, Student, Pro) and free with your own API key.");

  // Discovery Hints — sticky "Did You Know?" tips that surface the first
  // time a new user hits a feature worth knowing about.
  const discoveryHintsId = uuidv4();
  createNode(nodes, discoveryHintsId, aiId, "Did You Know? tips", "SecondBrainWare surfaces sticky discovery cards in the lower-right corner the first time you reach a feature worth knowing about — short, conversational, one-tip-at-a-time.\n\n**Examples (v1):**\n• First text selection in the editor → 'Reformat with AI is here' tip (points at the violet wand at the left end of the bubble menu)\n• Six seconds later → 'Smart Tools = your AI toolkit' tip (points at the sparkle icon in the toolbar)\n• First time you create an outline → 'Link one outline to another' tip, then 10 seconds later an 'Import and Export live in the toolbar' tip\n• First time you open a BYOK key entry in Settings → 'Bring your own API key for unlimited use' tip\n\n**How they behave:**\n• Tips do NOT auto-dismiss — click the 'Got it' button when you've read it\n• Multiple tips stagger so they never pile up\n• Each tip has the eyebrow 'Did You Know?' and a violet sparkle so they're distinguishable from regular toasts\n\n**Two ways to dismiss (2026-06-05):**\nEvery 'Did You Know?' card has TWO controls along its bottom edge: a checkbox labelled 'Don't show me this again', and the 'Got it' button.\n• **Just click 'Got it'** (checkbox UNCHECKED): the card disappears for now, but the same tip is eligible to pop up again the next time the same thing happens (e.g. the next time you select text). Useful when you want the card out of the way but a refresher later would be welcome.\n• **Check the box, then click 'Got it'**: the tip goes onto a permanent 'never show again' list and won't appear for you ever again — not even if you later switch Professional mode off.\n\n**Professional mode (turn off all tips):**\nSettings → Tips → 'Professional mode' is the master switch. Turn it ON to suppress every tip — anything currently visible disappears and no new tips will fire. Turn it OFF to restore the normal new-user behaviour: tips will fire again on their triggers — except anything you marked 'Don't show me again', which stays hidden forever. A brief confirmation card titled 'Welcome tips re-enabled' confirms the switch.\n\nUsed correctly, the tips drop off after the first week and you only see them again if SecondBrainWare ships a meaningful new feature.");

  // Local AI / Ollama
  const aiOllamaId = uuidv4();
  createNode(nodes, aiOllamaId, aiId, "Local AI / Ollama", "Run AI features using a local model instead of cloud services.\n\nSetup:\n1. Install Ollama (ollama.ai) on your machine — version 0.20+ required for Gemma 4 support\n2. Pull a model: ollama pull gemma4:e4b (recommended for most users)\n3. In IdiamPro: Settings > AI Provider\n4. Choose 'Local (Ollama)' or 'Auto'\n\n**Provider Options:**\n- Cloud: Uses cloud AI (default)\n- Local (Ollama): Uses your local Ollama instance on localhost:11434\n- Auto: Tries local first, falls back to cloud if unavailable\n\n**Recommended Models (Gemma 4 — released April 2026):**\n- gemma4:e2b — Lightweight (~1.5GB RAM), mobile-friendly, multimodal\n- gemma4:e4b — RECOMMENDED (~4GB RAM), multimodal, best balance for most systems\n- gemma4:26b — High quality (~16GB RAM), Mixture of Experts, fast despite size\n- gemma4:31b — Maximum quality (~24GB RAM), beats Llama 4 on benchmarks\n\n**Legacy fallback:**\n- llama3.2 — For systems with less than 4GB RAM\n\nIdiamPro automatically selects the best model installed based on your system memory. Gemma 4 models support text + image (multimodal), enabling local image analysis without sending to cloud.\n\nLocal AI keeps your data on your machine and works offline.");

  // AI Data Consent
  const aiConsentId = uuidv4();
  createNode(nodes, aiConsentId, aiId, "AI Data Consent & Privacy", "IdiamPro requires your explicit consent before sending data to AI services.\n\n**First-time consent:**\nWhen you use any AI feature for the first time, a consent dialog appears explaining which services process your data:\n- **Google Gemini** — text generation, content expansion, outline creation\n- **OpenAI** — podcast audio synthesis (text-to-speech)\n- **AssemblyAI** — audio transcription\n\nYou must click 'I Agree' to enable AI features. If you decline, all non-AI features remain fully functional.\n\n**Managing consent:**\nGo to Settings > Data & Privacy to toggle AI data processing on or off at any time.\n\n**Privacy Policy:**\nAvailable at /privacy. Your outlines are stored locally on your device and are never uploaded for storage. Data is only sent to AI services when you explicitly invoke an AI feature.");

  // Safety & Control
  createNode(nodes, aiSafetyId, aiId, "Safety & Control", "You're always in control:\n\n- All AI content is fully editable - change or delete anything\n- Preview mode shows changes before they're applied\n- No automatic modifications to your content\n- Auto-save preserves all changes (including AI content)\n- Undo by using browser back or editing content\n\nAI is a tool to help you - the final decisions are always yours.");

