  createNode(nodes, knowledgeChatId, aiId, "Ask Your Outlines", "Query your outlines with natural language. Ask questions, find information, and discover connections across your content using AI. (Renamed 2026-06-04 — previously called \"Knowledge Chat\".)\n\n**Access:** Smart Tools menu > Ask Your Outlines, or use the 🧠 Second Brain menu > Search Second Brain.\n\n**Three Modes:**\n- Current Outline — queries only the active outline\n- All Outlines — queries all your outlines at once\n- 🧠 Second Brain — queries only your Second Brain outline\n\nThe AI answers based only on your outline content, referencing specific sections and making cross-outline connections.\n\n**Streaming Responses:** Answers appear word-by-word as they're generated, so you see the first words within 1-2 seconds instead of waiting for the full response.", []);

  createNode(nodes, kcQueryId, knowledgeChatId, "Querying Your Outlines", "How to use Ask Your Outlines:\n\n1. Click the brain icon (blue) in the toolbar\n2. The chat dialog opens with your current outline loaded\n3. Type a question in natural language\n4. The AI responds using information from your outlines\n\n**Example questions:**\n- 'What are the key findings from my research?'\n- 'Summarize the Q1 goals'\n- 'What connections exist between marketing and product?'\n- 'Find everything related to budget constraints'");

  createNode(nodes, kcCurrentModeId, knowledgeChatId, "Current Outline Mode", "Queries only the currently selected outline.\n\nBest for:\n- Focused questions about one topic\n- Finding specific details within a document\n- Working with very large outlines\n\nThe context info bar shows the outline name, node count, and estimated token usage.");

  createNode(nodes, kcAllModeId, knowledgeChatId, "Second Brain Mode (All Outlines)", "Queries all your outlines simultaneously.\n\nBest for:\n- Finding connections across different topics\n- Research synthesis — 'What do my sources say about X?'\n- Memory recall — 'Where did I write about Y?'\n- Cross-referencing information\n\n**Desktop (Electron):** Uses a pre-built knowledge base file that's automatically kept in sync when you save, rename, or delete outlines.\n\n**Web:** Serializes all in-memory outlines on the fly.\n\nThe context info bar shows how many outlines and nodes are included.");

  createNode(nodes, kcTipsId, knowledgeChatId, "Tips & Use Cases", "**Research Synthesis:**\nImport multiple sources with Research & Import, then use Ask Your Outlines to ask cross-cutting questions.\n\n**Memory Recall:**\nCan't remember where you wrote something? Ask 'Where did I mention...' in All Outlines mode.\n\n**Finding Connections:**\nAsk 'What connections exist between [topic A] and [topic B]?' to discover relationships you might have missed.\n\n**Token Limits:**\n- A warning appears if context exceeds 500K tokens\n- If it exceeds 1M tokens, switch to Current Outline mode\n- Most outlines are well within limits");

  // === SECOND BRAIN ===
  const secondBrainGuideId = uuidv4();
  const sbSaveId = uuidv4();
  const sbSearchId = uuidv4();
